/** Request to create a new Order */
export interface ProtoDealerNewOrderReq {
  payloadType?:
    | ProtoCSPayloadType
    | undefined;
  /** Unique identifier of the Trader within environment */
  traderId: Long;
  /** The unique identifier of the Symbol in specific server environment within cTrader platform */
  symbolId: Long;
  /** The type of an Order - MARKET, LIMIT, STOP, MARKET_RANGE, STOP_LIMIT */
  orderType: ProtoOrderType;
  /** The trade direction - BUY or SELL */
  tradeSide: ProtoTradeSide;
  /** The volume represented in 0.01 of a unit (e.g. US$ 10.00 = 1000) */
  volume: Long;
  /** The limit price, can be specified for the LIMIT Order only */
  limitPrice?:
    | number
    | undefined;
  /** The stop price, can be specified for the STOP and the STOP_LIMIT Orders only */
  stopPrice?:
    | number
    | undefined;
  /** The specific Order execution or expiration instruction - GOOD_TILL_DATE, GOOD_TILL_CANCEL, IMMEDIATE_OR_CANCEL, FILL_OR_KILL, MARKET_ON_OPEN. Default: GOOD_TILL_CANCEL */
  timeInForce?:
    | ProtoTimeInForce
    | undefined;
  /** UNIX timestamp in milliseconds or the Order expiration. Should be set for the Good Till Date Orders */
  expirationTimestamp?:
    | Long
    | undefined;
  /** The absolute Stop Loss price (1.23456 for example). Not supported for the MARKER Orders */
  stopLoss?:
    | number
    | undefined;
  /** The absolute Take Profit price (1.23456 for example). Unsupported for the MARKER Orders */
  takeProfit?:
    | number
    | undefined;
  /** User-specified comment. MaxLength = 512 */
  comment?:
    | string
    | undefined;
  /** Technical field - to be filled with "ManagerAPI" */
  method?:
    | string
    | undefined;
  /** Base price to calculate relative slippage price for MARKET_RANGE Order */
  baseSlippagePrice?:
    | number
    | undefined;
  /** User-specified label. MaxLength = 100 */
  label?:
    | string
    | undefined;
  /** Technical field - to be filled with "ManagerAPI" */
  channel?:
    | string
    | undefined;
  /** Reference to the existing Position if the Order is intended to modify it */
  positionId?:
    | Long
    | undefined;
  /** Optional user-specific clientOrderId (similar to FIX ClOrderID). MaxLength = 50 */
  clientOrderId?:
    | string
    | undefined;
  /** Deprecated field, should not be used */
  clientToken?:
    | string
    | undefined;
  /** Relative Stop Loss that can be specified instead of the absolute as one. Specified in 1/100000 of unit of a price. For BUY stopLoss = entryPrice - relativeStopLoss, for SELL stopLoss = entryPrice + relativeStopLoss */
  relativeStopLoss?:
    | Long
    | undefined;
  /** Relative Take Profit that can be specified instead of the absolute one. Specified in 1/100000 of unit of a price. For BUY takeProfit = entryPrice + relativeTakeProfit, for SELL takeProfit = entryPrice - relativeTakeProfit */
  relativeTakeProfit?:
    | Long
    | undefined;
  /** Stake for Spread Betting */
  stake?:
    | Long
    | undefined;
  /** Price desired by the client as an execution price */
  desiredVWAP?:
    | number
    | undefined;
  /** If TRUE then stopLoss is guaranteed. Required to be set to TRUE for the Limited Risk accounts. */
  guaranteedStopLoss?:
    | boolean
    | undefined;
  /** If TRUE then tolerance check is applied and Order may be rejected due to significant price change. Applied only for B-book Orders */
  checkTolerance?:
    | boolean
    | undefined;
  /** If TRUE then a lot of server validations should be skipped: Symbol and Trader restrictions (market is closed, short selling disabled, account is disabled, GSL is not allowed, min\max volume, protection distances, etc.) */
  ignoreValidation?:
    | boolean
    | undefined;
  /** If TRUE then the Trailing Stop Loss is applied */
  trailingStopLoss?:
    | boolean
    | undefined;
  /** Trigger method for the STOP or the STOP_LIMIT pending Order */
  stopTriggerMethod?:
    | ProtoOrderTriggerMethod
    | undefined;
  /** Stop trigger method for SL/TP Order */
  stopLossTriggerMethod?:
    | ProtoOrderTriggerMethod
    | undefined;
  /** Slippage Distance for MARKET_RANGE and STOP_LIMIT Order */
  slippageInPoints?:
    | number
    | undefined;
  /** UNIX timestamp in milliseconds used to set time of the opening for MARKET_ON_OPEN Orders */
  desiredOpenTimestamp?: Long | undefined;
}

